// packages/canvas/src/objects/object-def.ts (doc comments trimmed)
export type ObjectHandles = "all" | "corners" | "none";
export type ObjectDragCapture = "descendants" | "none";
export interface TextEditingSpec {
  editable: boolean;
  markdown?: boolean;
}
export type ObjectColorRole = "shape" | "sticky" | "section";
export type ObjectButtonBorderPolicy = "painted" | "suppressed";

export interface ObjectDef {
  /** Registry key — the object `type` (every registered def's kind is an InteractiveCanvasObjectType). */
  kind: string;
  /** The object's world-layer renderer (receives the same props as stage/ObjectShape). */
  render: ComponentType<ObjectRenderProps>;
  /** This kind's global-CSS rules — CanvasStage composes its style tag from every registered def's css. */
  css: string;
  /** Per-type creation/placement defaults — stamped VERBATIM from state/schema/object-defaults.ts. */
  defaults: ObjectTypeDefaults;
  /** Palette role table this kind's color pick renders through (P1, §3.5). */
  colorRole: ObjectColorRole;
  buttonBorder: ObjectButtonBorderPolicy;   // "painted" | "suppressed"
  /** The kind's geometric outline (P3, D4): anchors, anchor dots, outline snap,
      and pointer hit-testing (D16) all derive from it. */
  outline: OutlineSpec;
  handles: ObjectHandles;
  dragCapture: ObjectDragCapture;
  /** Where and how this kind's `object.text` renders AND is edited (D3/D6/D14).
      Absent = the kind renders no object text at all (plus / or-junction / summing-junction). */
  textSlot?: TextSlot;
  textEditing: TextEditingSpec;
  /** This kind's selection toolbar: data-only control list. */
  toolbar?: ToolbarSpec;
  /** Picker metadata (P4, O7) — absent for kinds the Shapes panel never lists. */
  catalog?: ObjectCatalogMeta;
}

// packages/canvas/src/objects/object-def.ts
export interface ConnectorDef {
  kind: "connector";
  toolbar: ToolbarSpec;
  /** Connection color picks resolve through theme/palette.ts's "connector" role cells (resolveConnectorStroke). */
  colorRole: "connector";
  /** Labels edit in place at the routed midpoint, not via an object text slot. */
  labelEditing: "routed-midpoint";
}

// The instance lives in packages/canvas/src/connectors/def.ts:
export const connectorDef: ConnectorDef = {
  kind: "connector",
  toolbar: CONNECTOR_TOOLBAR, // color / text / dash / arrowhead
  colorRole: "connector",
  labelEditing: "routed-midpoint",
};

// packages/canvas/src/objects/shapes/shape-def.ts (doc comments trimmed)
export interface ShapeOutlineArgs {
  object: InteractiveCanvasObject;
  /** The color pick resolved through the "shape" palette role:
      fill + border (border is always a hex; every pick renders a bordered shape)
      + the fixed dark text color (D8). */
  colors: ResolvedShapeObjectColors;
  /** Resolved stroke width. */
  strokeWidth: number;
}

/** The VISUAL spec: how the shape paints (distinct from the geometric `outline`). */
export interface SilhouetteSpec {
  className?: string;
  silhouette?: (args: ShapeOutlineArgs) => ReactNode;
}

export type ShapeTextSpec = TextSlot | "none";

export interface ShapeDef {
  type: InteractiveCanvasObjectType;
  /** The `style.shape` variant this def renders. Usually same-named as `type`;
      differs where history diverged (sticky → "note", process → "rounded-rect"). */
  shape: NonNullable<CanvasObjectStyle["shape"]>;
  /** How the shape PAINTS (CSS class + optional SVG silhouette layer). */
  silhouette: SilhouetteSpec;
  /** Whether the outer button itself paints the shape border. Defaults to "painted". */
  buttonBorder?: ObjectButtonBorderPolicy;
  /** Geometric outline (D4) — omit for the bbox default (shapeObjectDef stamps BBOX_OUTLINE). */
  outline?: OutlineSpec;
  /** Text slot — omit for the "center" preset default; "none" = pure glyph, no text. */
  text?: ShapeTextSpec;
  /** This shape's global-CSS rules. */
  css?: string;
  /** Picker metadata — the catalog (objects/catalog.ts) derives entry labels/keywords from this. */
  catalog: ObjectCatalogMeta;
}

// packages/canvas/src/objects/text-slots.ts (doc comments trimmed)
/** Object-local rectangle (px, relative to the object's top-left corner). */
export interface LocalRect {
  x: number;
  y: number;
  width: number;
  height: number;
}

export type TextPlacement =
  | "center"
  | "below"
  | "inset-body"
  | "title-chip"
  | { rect: (object: InteractiveCanvasObject) => LocalRect };

/** Applied identically to the at-rest text and the in-place editor (D14). */
export interface SlotTypography {
  fontSizePx: number;
  fontWeight: number;
  /** CSS line-height value — unitless ("1.2") or px ("36px"). */
  lineHeight: string;
  textAlign: "center" | "left";
  /** One fixed dark text color everywhere (D8) — presets pick their exact value. */
  color: string;
  /** Omit to inherit the canvas font for monospace slots. */
  fontFamily?: string;
}

export interface TextSlot {
  placement: TextPlacement;
  typography: SlotTypography;
  /** "chip-scale" counter-scales when zoomed out (title-chip); everything else natural. */
  zoom: "natural" | "chip-scale";
  /** Optional compact cutoff for below-glyph labels. */
  compactBelowHeightPx?: number;
  verticalAlign: "top" | "center" | "bottom";
  multiline: boolean;
}

// packages/canvas/src/objects/text-slots.ts — the presets (values verbatim, others elided)
export const OBJECT_TEXT_COLOR = "#000000"; // the one object-text color (D8)

export const SHAPE_TEXT_TYPOGRAPHY: SlotTypography = {
  fontSizePx: 15,
  fontWeight: 700,
  lineHeight: "1.2",
  textAlign: "center",
  color: OBJECT_TEXT_COLOR,
};

/** "center" — inside the shape body, centered both ways. The default for shapes. */
export const CENTER_TEXT_SLOT: TextSlot = {
  placement: "center",
  typography: SHAPE_TEXT_TYPOGRAPHY,
  zoom: "natural",
  verticalAlign: "center",
  multiline: true,
};

/** "below" — bold band under the icon glyph. */
export function belowTextSlot(options?: { compactBelowHeightPx?: number }): TextSlot;
export const BELOW_TEXT_SLOT: TextSlot = belowTextSlot();

/** "inset-body" — padded multi-line body area (sticky): 24px/400, "36px" lines, left, top. */
export const INSET_BODY_TEXT_SLOT: TextSlot;

/** "title-chip" — floating chip, top-left, zoom counter-scaled (section): 16px/700, single-line. */
export const TITLE_CHIP_TEXT_SLOT: TextSlot;

/** The escape hatch: a def-provided object-local rect, shape-baseline typography unless overridden. */
export function rectTextSlot(
  rect: (object: InteractiveCanvasObject) => LocalRect,
  options?: Partial<Omit<TextSlot, "placement">>,
): TextSlot;

/** The ONE rect/typography source both the at-rest renderer and the in-place editor consume. */
export function resolveTextSlot(slot: TextSlot, object: InteractiveCanvasObject, zoom = 1): ResolvedTextSlot;

// packages/canvas/src/objects/geometry.ts
export type OutlineSpec =
  | { kind: "bbox" }
  | { kind: "polygon"; points: (bounds: CanvasBounds, object: InteractiveCanvasObject) => CanvasPoint[] }
  | { kind: "ellipse" };

// One shared spec object per outline family — a true-outline def declares its
// `outline` by referencing the SAME exported const the dispatch tables use
// (identity-asserted by objects/__tests__/geometry-def-agreement.test.ts):
export const BBOX_OUTLINE: OutlineSpec = { kind: "bbox" };
export const ELLIPSE_OUTLINE: OutlineSpec = { kind: "ellipse" };
export const DIAMOND_OUTLINE: OutlineSpec = { kind: "polygon", points: diamondPoints };
export const TRIANGLE_OUTLINE: OutlineSpec = {
  kind: "polygon",
  points: (bounds, object) => trianglePoints(bounds, object.direction === "down" ? "down" : "up"),
};
// … PILL_OUTLINE / ARROW_SHAPE_OUTLINE / PARALLELOGRAM_OUTLINE / PENTAGON_OUTLINE /
//   OCTAGON_OUTLINE / STAR_OUTLINE / PLUS_OUTLINE / CHEVRON_OUTLINE /
//   OFF_PAGE_CONNECTOR_OUTLINE / TRAPEZOID_OUTLINE / MANUAL_INPUT_OUTLINE /
//   HEXAGON_OUTLINE / JUNCTION_OUTLINE (= ELLIPSE_OUTLINE, deliberately the same object)

/** True-outline dispatch by object TYPE (16 keys); everything else falls back to bbox. */
export const OUTLINES_BY_TYPE: Partial<Record<InteractiveCanvasObjectType, OutlineSpec>>;

/** Secondary dispatch by `style.shape` — ONLY pill/diamond/ellipse, exactly the three
    the pre-P3 outlineShapeFor() switch consulted style for. */
export const OUTLINES_BY_STYLE_SHAPE: Partial<
  Record<NonNullable<CanvasObjectStyle["shape"]>, OutlineSpec>
> = {
  pill: PILL_OUTLINE,
  diamond: DIAMOND_OUTLINE,
  ellipse: ELLIPSE_OUTLINE,
};

// packages/canvas/src/objects/geometry.ts — verbatim, including the ordering contract
/**
 * Resolves the outline spec for an object. The ordering reproduces the
 * pre-P3 `outlineShapeFor()` switch VERBATIM — including its quirks — so
 * connection geometry is byte-identical (rationalizing dispatch is P4):
 *
 *   1. `type === "arrow-shape"` wins over everything;
 *   2. `type === "pill"` wins over a mismatched diamond/ellipse style
 *      (the old switch's pill check preceded the style-diamond check);
 *   3. a pill/diamond/ellipse `style.shape` override wins over the
 *      remaining TYPE checks (the old switch's style checks sat ABOVE the
 *      W5 type checks — e.g. `type: "triangle"` + `style.shape: "diamond"`
 *      resolves DIAMOND, while `type: "process"` + `style.shape:
 *      "triangle"` stays BBOX because triangle is never a style key);
 *   4. the type table;
 *   5. bbox fallback.
 *
 * NOTE this is deliberately NOT `objectDefFor`'s render-shape dispatch —
 * hit-testing (D16) and connection geometry stay consistent with each other
 * by both using THIS lookup. TODO(P4): unify outline dispatch with render
 * dispatch when defs consolidate.
 */
export function outlineSpecFor(object: InteractiveCanvasObject): OutlineSpec {
  if (object.type === "arrow-shape") return ARROW_SHAPE_OUTLINE;
  if (object.type === "pill") return PILL_OUTLINE;
  const styleShape = object.style?.shape;
  const styleSpec = styleShape === undefined ? undefined : OUTLINES_BY_STYLE_SHAPE[styleShape];
  if (styleSpec) return styleSpec;
  return OUTLINES_BY_TYPE[object.type] ?? BBOX_OUTLINE;
}

// packages/canvas/src/state/schema/colors.ts
/** The 10 FigJam hue families (black dropped per D12; "white" is a hue here, not a neutral escape hatch). */
export type CanvasHue =
  | "gray"
  | "red"
  | "orange"
  | "yellow"
  | "green"
  | "teal"
  | "blue"
  | "violet"
  | "pink"
  | "white";

/** The stored color ids: 10 picks, one per hue. */
export type CanvasColor = CanvasHue;

/** The 10 swatch ids in picker order. */
export const CANVAS_COLORS: readonly CanvasColor[] = CANVAS_HUES;

/** Type guard for the closed 10-id roster — use at schema/validator boundaries. */
export function isCanvasColor(value: unknown): value is CanvasColor;

// packages/canvas/src/theme/palette.ts
export type ShapeColors = {
  fill: string;
  /** Every shape pick renders with an ink border. */
  border: string;
};

export type SectionChipColors = {
  fill: string;
  border: string;
};

export type SectionColors = {
  tint: string;
  chip: SectionChipColors;
};

export type Swatch = {
  /** The picker preview: ink, except white previews as #FFFFFF with its contrast ring. */
  swatch: string;
  /** fill + ink border. */
  shape: ShapeColors;
  /** wash tint + title-chip fill/border. */
  section: SectionColors;
  /** Sticky fill role. */
  sticky: string;
  /** Connector stroke: ink, with white using gray. */
  connector: string;
};

export const CANVAS_PALETTE: Record<CanvasColor, Swatch>;

// The per-role resolvers — one per role table:
export function resolveShapeColors(color: CanvasColor): ShapeColors;
export function resolveSectionColors(color: CanvasColor): SectionColors;
export function resolveStickyFill(color: CanvasColor): string;
export function resolveConnectorStroke(color: CanvasColor): string;
export function resolveSwatchPreview(color: CanvasColor): string;

